28: 
29:   rpc StreamRoutes(stream discovery.v3.DiscoveryRequest)
30:       returns (stream discovery.v3.DiscoveryResponse) {
31:   }
32: 
33:   rpc DeltaRoutes(stream discovery.v3.DeltaDiscoveryRequest)
34:       returns (stream discovery.v3.DeltaDiscoveryResponse) {
35:   }
36: 
37:   rpc FetchRoutes(discovery.v3.DiscoveryRequest) returns (discovery.v3.DiscoveryResponse) {
38:     option (google.api.http).post = "/v3/discovery:routes";
39:     option (google.api.http).body = "*";
40:   }
41: }
